code = """import json
from collections import Counter

# 1. Get Product Order Item IDs
order_item_ids_raw = locals()['var_function-call-5114374313652700189']
# Handle potential # and clean IDs
valid_oids = set()
def clean_id(id_str):
    return id_str.lstrip('#')

for item in order_item_ids_raw:
    oid = item['Id']
    valid_oids.add(oid)
    valid_oids.add(clean_id(oid))
    valid_oids.add('#' + clean_id(oid))

# 2. Get Cases
cases_file = locals()['var_function-call-16753137479526333532']
with open(cases_file, 'r') as f:
    cases = json.load(f)

# 3. Filter and Count Issues
issue_counts = Counter()
for case in cases:
    oid = case.get('orderitemid__c')
    if oid in valid_oids:
        issue = case.get('issueid__c')
        if issue:
            issue_counts[issue] += 1

# 4. Find most common
most_common = issue_counts.most_common(1)

print("__RESULT__:")
print(json.dumps(most_common))"""

